func (s *InMemoryStore) GetOrCreateBalance(accountID, currency string) *AccountBalance {
	key := fmt.Sprintf("%s:%s", accountID, currency)
	if bal, ok := s.balances[key]; ok {
		return bal
	}
	bal := &AccountBalance{
		AvailableMinorUnits: 0,
		PendingMinorUnits:   0,
		Currency:            currency,
	}
	s.balances[key] = bal
	return bal
}

func (s *InMemoryStore) SaveTransaction(txn *pb.Transaction) {
	s.transactions[txn.TransactionId] = txn

	if txn.SourceAccountId != "" {
		s.accountTxns[txn.SourceAccountId] = append(s.accountTxns[txn.SourceAccountId], txn.TransactionId)
	}
	if txn.DestinationAccountId != "" && txn.DestinationAccountId != txn.SourceAccountId {
		s.accountTxns[txn.DestinationAccountId] = append(s.accountTxns[txn.DestinationAccountId], txn.TransactionId)
	}

	if txn.IdempotencyKey != "" {
		s.idempotencyKeys[txn.IdempotencyKey] = txn.TransactionId
	}
}

